import Database from 'better-sqlite3'
import path from 'path'

const DB_PATH = path.join(process.cwd(), 'counter.db')

let db: Database.Database

export function getDb(): Database.Database {
  if (!db) {
    db = new Database(DB_PATH)
    db.pragma('journal_mode = WAL')
    initDb(db)
  }
  return db
}

function initDb(db: Database.Database): void {
  db.exec(`
    CREATE TABLE IF NOT EXISTS counter (
      id INTEGER PRIMARY KEY CHECK (id = 1),
      count INTEGER NOT NULL DEFAULT 0
    );
    INSERT OR IGNORE INTO counter (id, count) VALUES (1, 0);
  `)
}

export function getCount(): number {
  const db = getDb()
  const row = db.prepare('SELECT count FROM counter WHERE id = 1').get() as { count: number }
  return row.count
}

export function incrementCount(): number {
  const db = getDb()
  const row = db.prepare(
    'UPDATE counter SET count = count + 1 WHERE id = 1 RETURNING count'
  ).get() as { count: number }
  return row.count
}

import { createServerFn } from '@tanstack/react-start'
import { getCount, incrementCount } from '../db'

export const getCounterValue = createServerFn({ method: 'GET' }).handler(async () => {
  return getCount()
})

export const incrementCounter = createServerFn({ method: 'POST' }).handler(async () => {
  return incrementCount()
})

